SourceCode.Declaration:
/// <summary>
/// Data contract for the RO SAF-T generation dialog.
/// Holds the reporting period entered by the user.
/// </summary>
[DataContract]
internal final class SAFTRoGenerateContract
{
    private FromDate fromDate;
    private ToDate   toDate;

}

Method.Source:
/// <summary>
/// Gets or sets the start date of the reporting period.
/// </summary>
/// <param name = "_fromDate">The start date.</param>
/// <returns>The start date of the reporting period.</returns>
[DataMember, SysOperationLabel(literalStr("@ROSaft:FromDate")), SysOperationDisplayOrder('1')]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

/// <summary>
/// Gets or sets the end date of the reporting period.
/// </summary>
/// <param name = "_toDate">The end date.</param>
/// <returns>The end date of the reporting period.</returns>
[DataMember, SysOperationLabel(literalStr("@ROSaft:ToDate")), SysOperationDisplayOrder('2')]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}
